<?php

function findMaxAverage(array $nums, int $k): float {
    $len = count($nums);

    if($len < $k) return -1;

    $l = 0;
    $r = $k;

    $sum = sumArray(array_slice($nums, $l, $r));
    $result = $sum;

    while($r < $len) {
        $sum = $sum - $nums[$l] + $nums[$r];

        if($sum > $result){
            $result = $sum;
        }

        $l++;
        $r++;
    }

    return $result / $k;
}

function sumArray(array $nums): int {
    $sum = 0;
    foreach($nums as $num) {
        $sum += $num;
    }
    return $sum;
}

